/**
 * ASR Client — Whisper-compatible speech-to-text
 *
 * Supports any OpenAI-format /v1/audio/transcriptions endpoint.
 * Tested providers: SiliconFlow (api.siliconflow.cn)
 *
 * @module asr-client
 */

const DEFAULT_ENDPOINT = 'https://api.siliconflow.cn/v1/audio/transcriptions';

/**
 * @param {string} audioBase64 - base64-encoded audio (without data URI prefix)
 * @param {string} mimeType - e.g. 'audio/webm;codecs=opus' or 'audio/webm'
 * @param {string} apiKey - ASR API key
 * @param {string} [endpoint] - Whisper-compatible endpoint URL
 * @returns {Promise<{text: string}>}
 */
async function transcribe(audioBase64, mimeType, apiKey, endpoint, modelName) {
  if (!apiKey) throw new Error('ASR_KEY_MISSING');
  if (!audioBase64) throw new Error('ASR_NO_AUDIO');

  // 如果 endpoint 不是合法 URL（比如误填了 API Key），回退到默认
  const url = (endpoint && endpoint.startsWith('http')) ? endpoint : DEFAULT_ENDPOINT;

  // 将 base64 解码为二进制
  const binaryStr = atob(audioBase64);
  const bytes = new Uint8Array(binaryStr.length);
  for (let i = 0; i < binaryStr.length; i++) {
    bytes[i] = binaryStr.charCodeAt(i);
  }

  const ext = mimeType.includes('webm') ? 'webm' : 'ogg';
  const blob = new Blob([bytes], { type: mimeType });

  const form = new FormData();
  form.append('file', blob, `recording.${ext}`);
  form.append('model', modelName || 'FunAudioLLM/SenseVoiceSmall');
  // 明确指定中文语种，提升识别准确率
  form.append('language', 'zh');

  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 10000);

  try {
    const res = await fetch(url, {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${apiKey}` },
      body: form,
      signal: controller.signal
    });

    clearTimeout(timeout);

    if (res.status === 401) throw new Error('ASR_AUTH_ERROR');
    if (res.status === 429) throw new Error('ASR_RATE_LIMIT');
    if (!res.ok) {
      await res.text().catch(() => '');
      throw new Error(`ASR_HTTP_${res.status}`);
    }

    const data = await res.json();

    const text = data.text?.trim();
    if (!text) throw new Error('ASR_EMPTY');

    return { text };
  } catch (e) {
    clearTimeout(timeout);
    if (e.name === 'AbortError') throw new Error('ASR_TIMEOUT');
    if (e.message?.startsWith('ASR_')) throw e;
    throw new Error('ASR_NETWORK');
  }
}

// ===== lib/tts-client.js =====

/**
 * TTS Client — SiliconFlow 文本转语音
 *
 * 端点: https://api.siliconflow.cn/v1/audio/speech
 * 模型: FunAudioLLM/CosyVoice2-0.5B
 * 音色: claire (温柔女声)
 *
 * @module tts-client
 */

const TTS_ENDPOINT = 'https://api.siliconflow.cn/v1/audio/speech';
const TTS_MODEL = 'FunAudioLLM/CosyVoice2-0.5B';
const TTS_VOICE = 'FunAudioLLM/CosyVoice2-0.5B:claire';

// 统一使用 claire 音色（中文/英文均支持）
function pickVoice(text) {
  return TTS_VOICE;
}

/**
 * 将文本转为语音，返回 base64 编码的 MP3
 * @param {string} text - 要合成的文本
 * @param {string} apiKey - SiliconFlow API Key
 * @returns {Promise<string>} base64-encoded MP3 data (不含 data URI 前缀)
 */
async function synthesize(text, apiKey) {
  if (!apiKey) throw new Error('TTS_KEY_MISSING');
  if (!text) throw new Error('TTS_NO_TEXT');

  const payload = {
    model: TTS_MODEL,
    input: text,
    voice: pickVoice(text),
    response_format: 'mp3'
  };

  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 15000);

  try {
    const res = await fetch(TTS_ENDPOINT, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(payload),
      signal: controller.signal
    });

    clearTimeout(timeout);

    if (res.status === 401) throw new Error('TTS_AUTH_ERROR');
    if (res.status === 429) throw new Error('TTS_RATE_LIMIT');
    if (!res.ok) throw new Error(`TTS_HTTP_${res.status}`);

    const arrayBuffer = await res.arrayBuffer();
    const bytes = new Uint8Array(arrayBuffer);

    // 转为 base64
    let binary = '';
    for (let i = 0; i < bytes.length; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  } catch (e) {
    clearTimeout(timeout);
    if (e.name === 'AbortError') throw new Error('TTS_TIMEOUT');
    if (e.message?.startsWith('TTS_')) throw e;
    throw new Error('TTS_NETWORK');
  }
}

